'use client'

import * as React from 'react'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs'
import { cn } from '@/lib/utils'
import type { PhotoAssetWithUrl } from '@/db/queries/photos'
import { timelineStageLabels } from '@/validations/photo'
import type { TimelineStage } from '@/types'

// ─── Types ──────────────────────────────────────────────────────────

interface PhotoComparisonProps {
  patientId: string
  procedureRecordId?: string
}

type ComparisonMode = 'side-by-side' | 'overlay' | 'slider'

// ─── Component ──────────────────────────────────────────────────────

export function PhotoComparison({
  patientId,
  procedureRecordId,
}: PhotoComparisonProps) {
  const [allPhotos, setAllPhotos] = useState<PhotoAssetWithUrl[]>([])
  const [loading, setLoading] = useState(true)
  const [mode, setMode] = useState<ComparisonMode>('side-by-side')
  const [photoIdA, setPhotoIdA] = useState<string>('')
  const [photoIdB, setPhotoIdB] = useState<string>('')
  const [urlA, setUrlA] = useState<string | null>(null)
  const [urlB, setUrlB] = useState<string | null>(null)
  const [loadingUrls, setLoadingUrls] = useState(false)
  const [opacity, setOpacity] = useState(50)
  const [sliderPosition, setSliderPosition] = useState(50)
  const sliderContainerRef = useRef<HTMLDivElement>(null)
  const isDragging = useRef(false)

  // Load all photos for patient
  useEffect(() => {
    async function load() {
      setLoading(true)
      try {
        const params = new URLSearchParams({ patientId })
        if (procedureRecordId) params.set('procedureRecordId', procedureRecordId)
        const res = await fetch(`/api/photos?${params}`)
        const result = await res.json()
        if (result.success && result.data) {
          const photos = result.data.flatMap((s: { photos: PhotoAssetWithUrl[] }) => s.photos)
          setAllPhotos(photos)
        }
      } finally {
        setLoading(false)
      }
    }
    load()
  }, [patientId, procedureRecordId])

  // Load signed URLs when photos are selected
  useEffect(() => {
    if (!photoIdA || !photoIdB) {
      setUrlA(null)
      setUrlB(null)
      return
    }

    async function loadUrls() {
      setLoadingUrls(true)
      try {
        const params = new URLSearchParams({ photoIdA, photoIdB })
        const res = await fetch(`/api/photos?${params}`)
        const result = await res.json()
        if (result.success && result.data) {
          setUrlA(result.data.urlA)
          setUrlB(result.data.urlB)
        }
      } finally {
        setLoadingUrls(false)
      }
    }
    loadUrls()
  }, [photoIdA, photoIdB])

  // Slider drag handlers
  const handleSliderMouseDown = useCallback(() => {
    isDragging.current = true
  }, [])

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging.current || !sliderContainerRef.current) return
      const rect = sliderContainerRef.current.getBoundingClientRect()
      const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width))
      setSliderPosition((x / rect.width) * 100)
    }

    const handleMouseUp = () => {
      isDragging.current = false
    }

    const handleTouchMove = (e: TouchEvent) => {
      if (!isDragging.current || !sliderContainerRef.current) return
      const rect = sliderContainerRef.current.getBoundingClientRect()
      const x = Math.max(0, Math.min(e.touches[0].clientX - rect.left, rect.width))
      setSliderPosition((x / rect.width) * 100)
    }

    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)
    window.addEventListener('touchmove', handleTouchMove)
    window.addEventListener('touchend', handleMouseUp)

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)
      window.removeEventListener('touchmove', handleTouchMove)
      window.removeEventListener('touchend', handleMouseUp)
    }
  }, [])

  const getPhotoLabel = useCallback(
    (photo: PhotoAssetWithUrl) => {
      const stage = photo.timelineStage
        ? timelineStageLabels[photo.timelineStage as TimelineStage]
        : 'Sem estágio'
      const name = photo.originalFilename
        ? photo.originalFilename.length > 20
          ? photo.originalFilename.slice(0, 20) + '...'
          : photo.originalFilename
        : 'Foto'
      return `${stage} — ${name}`
    },
    []
  )

  const photoItems = useMemo(() => {
    const map: Record<string, string> = {}
    for (const p of allPhotos) {
      map[p.id] = getPhotoLabel(p)
    }
    return map
  }, [allPhotos, getPhotoLabel])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="size-6 animate-spin text-sage" />
        <span className="ml-2 text-sm text-mid">Carregando fotos...</span>
      </div>
    )
  }

  if (allPhotos.length < 2) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-mid">
        <p className="text-sm">E necessario pelo menos 2 fotos para comparacao.</p>
      </div>
    )
  }

  return (
    <div className="space-y-4">
      {/* Photo selectors */}
      <div className="flex flex-wrap items-end gap-4">
        <div className="space-y-1.5">
          <Label className="uppercase tracking-wider text-xs text-mid">Foto A</Label>
          <Select items={photoItems} value={photoIdA} onValueChange={(v) => v && setPhotoIdA(v)}>
            <SelectTrigger className="w-64 border-sage/20">
              <SelectValue placeholder="Selecione a foto A" />
            </SelectTrigger>
            <SelectContent>
              {allPhotos.map((p) => (
                <SelectItem key={p.id} value={p.id} disabled={p.id === photoIdB}>
                  {getPhotoLabel(p)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div className="space-y-1.5">
          <Label className="uppercase tracking-wider text-xs text-mid">Foto B</Label>
          <Select items={photoItems} value={photoIdB} onValueChange={(v) => v && setPhotoIdB(v)}>
            <SelectTrigger className="w-64 border-sage/20">
              <SelectValue placeholder="Selecione a foto B" />
            </SelectTrigger>
            <SelectContent>
              {allPhotos.map((p) => (
                <SelectItem key={p.id} value={p.id} disabled={p.id === photoIdA}>
                  {getPhotoLabel(p)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Mode selector */}
      <Tabs value={mode} onValueChange={(v) => setMode(v as ComparisonMode)}>
        <TabsList>
          <TabsTrigger value="side-by-side">Lado a Lado</TabsTrigger>
          <TabsTrigger value="overlay">Sobreposição</TabsTrigger>
          <TabsTrigger value="slider">Slider</TabsTrigger>
        </TabsList>

        {/* Comparison views */}
        {loadingUrls ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="size-6 animate-spin text-sage" />
          </div>
        ) : !urlA || !urlB ? (
          <div className="flex items-center justify-center py-12 text-mid">
            <p className="text-sm">Selecione duas fotos para comparar.</p>
          </div>
        ) : (
          <>
            {/* Side by side */}
            <TabsContent value="side-by-side">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <p className="text-center text-xs font-medium text-mid uppercase tracking-wider">Foto A</p>
                  <div className="overflow-hidden rounded-[3px] border border-[#E8ECEF] shadow-[0_1px_4px_rgba(0,0,0,0.06)]">
                    <img
                      src={urlA}
                      alt="Foto A"
                      className="h-auto w-full object-contain"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <p className="text-center text-xs font-medium text-mid uppercase tracking-wider">Foto B</p>
                  <div className="overflow-hidden rounded-[3px] border border-[#E8ECEF] shadow-[0_1px_4px_rgba(0,0,0,0.06)]">
                    <img
                      src={urlB}
                      alt="Foto B"
                      className="h-auto w-full object-contain"
                    />
                  </div>
                </div>
              </div>
            </TabsContent>

            {/* Overlay */}
            <TabsContent value="overlay">
              <div className="space-y-3">
                <div className="flex items-center gap-3">
                  <Label className="shrink-0 text-xs text-mid uppercase tracking-wider">Opacidade: {opacity}%</Label>
                  <input
                    type="range"
                    min={0}
                    max={100}
                    value={opacity}
                    onChange={(e) => setOpacity(Number(e.target.value))}
                    className="h-2 w-48 cursor-pointer appearance-none rounded-full bg-petal accent-sage"
                  />
                </div>
                <div className="relative overflow-hidden rounded-[3px] border border-[#E8ECEF] shadow-[0_1px_4px_rgba(0,0,0,0.06)]">
                  <img
                    src={urlA}
                    alt="Foto A"
                    className="h-auto w-full object-contain"
                  />
                  <img
                    src={urlB}
                    alt="Foto B"
                    className="absolute inset-0 h-full w-full object-contain"
                    style={{ opacity: opacity / 100 }}
                  />
                </div>
              </div>
            </TabsContent>

            {/* Slider */}
            <TabsContent value="slider">
              <div
                ref={sliderContainerRef}
                className="relative cursor-col-resize select-none overflow-hidden rounded-[3px] border border-[#E8ECEF] shadow-[0_1px_4px_rgba(0,0,0,0.06)]"
              >
                {/* Right image (Photo B) - full width background */}
                <img
                  src={urlB}
                  alt="Foto B"
                  className="h-auto w-full object-contain"
                  draggable={false}
                />

                {/* Left image (Photo A) - clipped by slider position */}
                <div
                  className="absolute inset-0"
                  style={{
                    clipPath: `polygon(0 0, ${sliderPosition}% 0, ${sliderPosition}% 100%, 0 100%)`,
                  }}
                >
                  <img
                    src={urlA}
                    alt="Foto A"
                    className="h-full w-full object-contain"
                    draggable={false}
                  />
                </div>

                {/* Divider line */}
                <div
                  className="absolute top-0 bottom-0 z-10 w-0.5 bg-white shadow-[0_0_6px_rgba(0,0,0,0.3)]"
                  style={{ left: `${sliderPosition}%` }}
                >
                  {/* Drag handle */}
                  <div
                    className="absolute top-1/2 left-1/2 flex size-9 -translate-x-1/2 -translate-y-1/2 items-center justify-center rounded-full border-2 border-white bg-forest shadow-lg transition-transform hover:scale-110"
                    onMouseDown={handleSliderMouseDown}
                    onTouchStart={handleSliderMouseDown}
                  >
                    <svg
                      width="14"
                      height="14"
                      viewBox="0 0 14 14"
                      fill="none"
                      className="text-white"
                    >
                      <path
                        d="M4 3L1 7L4 11M10 3L13 7L10 11"
                        stroke="currentColor"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </div>
                </div>

                {/* Labels */}
                <div className="absolute top-2 left-2 rounded bg-black/50 px-2 py-0.5 text-xs text-white">
                  A
                </div>
                <div className="absolute top-2 right-2 rounded bg-black/50 px-2 py-0.5 text-xs text-white">
                  B
                </div>
              </div>
            </TabsContent>
          </>
        )}
      </Tabs>
    </div>
  )
}
